    teamId: '<TEAM_ID>'
)

// Check if user has specific role
final membership = response.memberships.firstWhere(
    (m) => m.userId == '<USER_ID>',
    orElse: () => null
)
final isAdmin = membership?.roles.contains('admin') ?? false
```
