    url: 'https://example.com/image.jpg',
    width: 800
});

// Resize by height only (width calculated automatically)
const heightOnly = avatars.getImage({
    url: 'https://example.com/image.jpg',
    height: 600
});

// Resize to specific dimensions
const specificSize = avatars.getImage({
    url: 'https://example.com/image.jpg',
    width: 800,
    height: 600
});
```
