// src/components/IdeasForm.tsx
'use client';

import { useIdeas } from '../hooks/useIdeas';
import { useAuth } from '../hooks/useAuth';

export default function IdeasForm() {
    const { add } = useIdeas();
    const { current: user } = useAuth();

